import{_ as s,o as a,c as t,ag as r}from"./chunks/framework.ETe_P6d1.js";const e="/kaiping-reports/assets/1.d7S_vhP_.png",i="/kaiping-reports/assets/2.CTJYv7cc.png",o="/kaiping-reports/assets/3.MA9SBTxA.png",n="/kaiping-reports/assets/4.CWk40TAT.png",m="/kaiping-reports/assets/5.BuMXqWXS.png",_="/kaiping-reports/assets/6.C-8VGjnE.png",c="/kaiping-reports/assets/7.D62nYeW5.png",g="/kaiping-reports/assets/8.Cn3xGrHr.png",l="/kaiping-reports/assets/9.BcPdsnqO.png",h="/kaiping-reports/assets/10.4jtZIV-x.png",d="/kaiping-reports/assets/11.CWnc8WuQ.png",k="/kaiping-reports/assets/12.FVnNaw6S.png",u="/kaiping-reports/assets/13.BA71C76q.png",q="/kaiping-reports/assets/14.DgZCAZCy.png",b="/kaiping-reports/assets/15.B7Rl7Sje.png",f="/kaiping-reports/assets/16.Dmd7KfsF.png",P="/kaiping-reports/assets/17.BjE6s1CD.png",x="/kaiping-reports/assets/18.BQa_5HHP.png",C="/kaiping-reports/assets/19.Fc8RBsa-.png",B="/kaiping-reports/assets/20.Dr5sPbEz.png",S="/kaiping-reports/assets/21.CxqXoBUd.png",T="/kaiping-reports/assets/22.CKQum6rv.png",A="/kaiping-reports/assets/23.BgcevgN_.png",D="/kaiping-reports/assets/24.CiY3d9vR.png",v="/kaiping-reports/assets/25.DQw_1PLM.png",$=JSON.parse('{"title":"立园地面铺装的纹样类型与空间分布调研报告","description":"","frontmatter":{"title":"立园地面铺装的纹样类型与空间分布调研报告"},"headers":[],"relativePath":"reports/覃紫晴/覃紫晴_调研报告.md","filePath":"reports/覃紫晴/覃紫晴_调研报告.md"}'),V={name:"reports/覃紫晴/覃紫晴_调研报告.md"};function E(M,p,N,W,j,Q){return a(),t("div",null,[...p[0]||(p[0]=[r('<h1 id="立园地面铺装的纹样类型与空间分布调研报告" tabindex="-1">立园地面铺装的纹样类型与空间分布调研报告 <a class="header-anchor" href="#立园地面铺装的纹样类型与空间分布调研报告" aria-label="Permalink to &quot;立园地面铺装的纹样类型与空间分布调研报告&quot;">​</a></h1><p># 立园地面铺装的纹样类型与空间分布</p><p>——开平近代建筑调研报告</p><p>考察地点：广东省江门市开平市</p><p>考察时间：2026年3月31日</p><p>考察学生：覃紫晴</p><p>指导老师：石拓</p><p>本次开平近代建筑考察以立园地面铺装为核心研究对象，立面构件与园林构筑物作为辅助参照。考察发现，立园铺装呈现纹样类型多样、空间分布有别的特征，花砖部分遵循统一的模数体系。核心问题为：铺装纹样的选择是否与空间等级、功能属性相关？其拼贴逻辑是否与立园整体中西融合的营造逻辑一致？考察时间为2026年4月，主要方法为实地观察与图像记录。</p><p>立园位于开平市塘口镇赓华村，是旅美华侨谢维立于1926年至1936年间兴建的私家园林，现为全国重点文物保护单位。核心建筑包括泮立楼、泮文楼、炯庐、毓培别墅及碉楼乐天楼等。立园采用博物馆式遗产保护，完整保留原始铺装细节，为细部观察提供了完整样本。</p><p>本部分为报告核心内容，从纹样类型与空间分布两个层面进行记录。</p><h3 id="_3-1-纹样类型" tabindex="-1">3.1 纹样类型 <a class="header-anchor" href="#_3-1-纹样类型" aria-label="Permalink to &quot;3.1 纹样类型&quot;">​</a></h3><p>立园铺装材料分为彩色水泥花砖与手工水磨石两大类。全园区花砖遵循统一模数体系，单块砖尺寸约为30cm×30cm（目测）。</p><p>彩色水泥花砖的纹样可分为两类。第一类为几何重复纹，包括菱形、六边形、方格交错、三角锯齿纹、连环几何纹等单元化纹样，排布规整，多用于铺装边框或过渡空间主区。第二类为卷草纹与花卉纹的融合体，以西洋卷草的曲线骨架结合中式团花的放射状构图，形成中西融合的复合纹样，主要用于核心空间的中心主区。</p><p><img src="'+e+'" alt="image 1"></p><p><img src="'+i+'" alt="image 2"></p><p><em>（图1：菱形方格交错单元化纹样。作者自摄）（图2：卷草纹与花卉纹的融合复合纹样。作者自摄）</em></p><p>手工水磨石在立园中存在三种不同的应用方式，分别对应不同空间类型。</p><p>第一种为楼梯与扶手等垂直交通空间的水磨石。以进口水泥为基底，掺入开平本土贝壳碎与碎石骨料，现场浇筑后打磨抛光，采用“中心主区加双侧条状边框”的标准化设计。中心踏步为赭红色水磨石主区，双侧以米白色水磨石带嵌黑色菱形装饰块，外侧以米黄色细条收边，侧边与扶手采用灰绿色水磨石现浇成型。纹样仅以几何菱形点缀，优先满足通行功能。</p><p>第二种为高层厅堂的整铺现浇水磨石。无预制花砖拼接缝隙，是立园铺装体系中高层空间的专属类型。铺装延续立园“中心主纹加多层边框”的通用设计逻辑，以暖黄色水磨石为基底，中心设方形装饰框，框内以红色三角形为核心视觉，框边以绿色为底点缀连续小型花卉纹，线条简洁利落，无底层空间的繁复卷草与星芒纹样。边框由多色三角锯齿纹、宽幅色带分层组成，色彩层次清晰，秩序感强。其主色调以暖黄、深紫红为主，区别于底层花砖的赭红、米黄与深灰经典配色，同时保留全园区通用的装饰色系。</p><p>第三种为乐天楼碉楼内部的整铺式水磨石。无拼接缝隙，以进口水泥为基底均匀掺入浅色碎石与本地贝壳碎骨料，表面温润细腻，是立园碉楼内部独有的整幅式地面装饰。其纹样为典型的装饰艺术几何风格，采用严格的中心对称布局，视觉核心为圆形构图，内部以黑白相间的棋盘格为基底，叠加方形与扇形组合的几何块面，线条硬朗利落，无多余曲线装饰。纹样外围由多层直线几何边框环绕收束，色彩以灰绿色与米白色为基调，穿插赭红色与黑色线条及块面，层次清晰、对比柔和。</p><p>水磨石工艺在民国时期随华侨返乡传入，与碉楼建造中使用的“红毛泥”（进口水泥）技术同源，是侨乡近代建造技术在装饰层面的延伸。</p><p><img src="'+o+'" alt="image 3"></p><p><em>（图3：水磨石工艺特写，作者自摄）</em></p><h3 id="_3-2-空间分布" tabindex="-1">3.2 空间分布 <a class="header-anchor" href="#_3-2-空间分布" aria-label="Permalink to &quot;3.2 空间分布&quot;">​</a></h3><p>铺装纹样的选择与空间等级及功能分区存在明确的对应关系，全园区形成完整的多级梯度。</p><p>底层核心公共空间以泮立楼主厅为代表。室内铺装采用民国经典花砖铺设，纹样中心由四块瓷砖拼接成一个完整的大圆团花。核心纹样为西洋卷草纹与花卉纹的融合体，线条繁复且色彩层次丰富，主色调涵盖赭红、米黄与深灰。单元砖边缘辅以三角形、连环状的条形几何纹作为边框，通过色彩分割界定空间单元，形成“中心花卉加条形边框”的典型欧式花砖布局。四砖拼合的大型复合卷草团花、四周有一圈边框嵌套、具有一定的色彩对比，打造出核心公共空间的仪式感，彰显园主身份与待客礼仪。</p><p><img src="'+n+'" alt="image 4"></p><p><img src="'+m+'" alt="image 5"></p><p><em>（图4、图5：泮立楼主厅铺装纹样。作者自摄）</em></p><p>高层公共空间以高层厅堂为代表。地面为整铺现浇手工水磨石，无花砖拼接缝隙，纹样延续“中心主纹加多层边框”的设计逻辑，但中心仅设方形装饰框与红色三角形几何纹，边框由三角锯齿纹与宽幅色带分层组成，无底层主厅的繁复卷草与团花。主色调为暖黄与深紫红，区别于底层花砖的经典配色。纹样复杂度介于底层主厅与过渡空间之间，弱化了仪式感、但仍需保持公共性的空间属性。</p><p><img src="'+_+'" alt="image 6"></p><p><img src="'+c+'" alt="image 7"></p><p><em>（图6：高层厅堂整铺水磨石地面。作者自摄）（图7：高层厅堂整铺水磨石地面特写。作者自摄）</em></p><p>底层次核心公共空间以泮文楼主厅为代表。大厅整体采用统一的八角星芒主纹样，但通过一条独立的条状铺装带，在视觉上清晰地界定出中心礼仪区与边缘通行区。该条状带由深灰三角锯齿纹、赭红连环几何纹与如意云头点缀纹三层纹样组成，所有元素均与泮立楼铺装边框同源，遵循统一模数体系。这种设计是中式厅堂礼序与西式装饰工艺的深度融合：以中式传统“中心待客区”的礼序为内核，采用西方近代花砖边框工艺实现空间分区，在保持主纹样统一性的同时完成空间功能与视觉层次的双重划分。与泮立楼主厅“大团花加多层边框”的极致仪式感类似，同时适配核心公共空间的定位。</p><p><img src="'+g+'" alt="image 8"></p><p><img src="'+l+'" alt="image 9"></p><p><em>（图8、图9：泮文楼大厅铺装纹样。作者自摄）</em></p><p>过渡半公共空间以阳台与走廊为代表。走廊铺装延续全园区统一的模数体系，采用“中心简化几何主纹加双侧条状边框”的框式布局，与泮文楼大厅的条状带界定逻辑完全一致。中心主区为简化版几何复合纹，纹样复杂度介于厅堂主纹与居住空间简化纹之间；双侧条状边框由深灰三角锯齿纹、赭红连环几何纹组成，纹样元素与全园区铺装边框同源，清晰界定空间边界。阳台作为连接室内厅堂与室外园林的半公共缓冲空间，通过整体采用统一的八角星芒主纹样，既延续公共空间的装饰逻辑，又适配通行与观景的过渡功能。</p><p><img src="'+h+'" alt="10"></p><p><img src="'+d+'" alt="11"></p><p><em>（图10：走廊铺装。作者自摄）（图11：阳台铺装。作者自摄）</em></p><p>楼梯与扶手等垂直交通空间进一步完善了这一层级。铺装没有用装饰性强的彩色花砖，选用耐磨、防潮的手工水磨石。楼梯水磨石采用“中心主区加双侧条状边框”的标准化设计：中心踏步为赭红色水磨石主区，双侧以米白色水磨石带嵌黑色菱形装饰块，外侧以米黄色细条收边。纹样仅以几何菱形做点缀，复杂度远低于厅堂花砖，既延续了全园区“主区加边框”的设计逻辑，又优先满足通行功能。</p><p><img src="'+k+'" alt="12"></p><p><em>（图12：立园楼梯水磨石铺装。作者自摄）</em></p><p>私密居住空间以卧室与偏房为代表。铺装采用四砖拼合的小型简化四瓣海棠团花，纹样为几何化抽象花卉，线条简洁、色彩素雅，仅保留单层基础几何边框，整体以连续网格状均匀排布，无明显视觉焦点。与主厅的繁复团花形成明确对比，也有延续跟厅堂一样的铺装，但相对简化，适配私密空间的日常使用需求。这种同一工艺体系下的差异化设计，直观体现了立园以铺装区分空间等级的营造观念。</p><p><img src="'+u+'" alt="13"></p><p><img src="'+q+'" alt="14"></p><p><em>（图13：卧室与偏房铺装。作者自摄）</em></p><p>防御性公共空间以乐天楼碉楼内部为代表。地面为现场整铺现浇的手工水磨石，无拼接缝隙，是立园碉楼内部独有的整幅式地面装饰。纹样为典型的装饰艺术几何风格，采用严格中心对称布局，以黑白棋盘格为基底叠加方形与扇形几何块面，外围多层直线边框收束。与别墅区铺装按空间功能区分纹样复杂度的逻辑不同，乐天楼铺装以整铺式水磨石的规整的纹样适配碉楼的防御性公共属性以及特殊性。</p><p><img src="'+b+'" alt="15"></p><p><em>（图14：乐天楼整铺式水磨石地面。作者自摄）</em></p><p>空间等级体系小结。立园铺装形成了完整的多级梯度：底层核心公共空间采用花砖繁复团花，高层公共空间采用水磨石简化几何纹，底层次核心公共空间采用花砖几何纹加条状分区，过渡半公共空间采用水磨石或花砖简化纹，私密居住空间采用花砖素雅团花，防御性公共空间采用整铺式水磨石装饰艺术纹样。全园区花砖遵循统一的模数与“主区加边框”的设计逻辑，边框纹样元素（三角锯齿纹、连环几何纹）在不同空间通用。水磨石则根据空间属性分化为三种类型：高层厅堂的暖黄色几何纹水磨石、楼梯的赭红色功能水磨石、乐天楼的灰绿色装饰艺术水磨石。这一体系直观体现了立园以铺装区分空间等级与功能的营造逻辑：园主根据空间属性对铺装进行针对性设计，同一工艺体系下仅做差异化处理，既保证整座园林装饰风格的整体性，又实现空间等级的视觉区分。</p><p>本节仅作简要辅助记录，印证立园整体营造逻辑与铺装拼贴逻辑的一致性。</p><h3 id="_4-1-立面构件" tabindex="-1">4.1 立面构件 <a class="header-anchor" href="#_4-1-立面构件" aria-label="Permalink to &quot;4.1 立面构件&quot;">​</a></h3><p>别墅柱式分室内装饰壁柱与室外承重柱两类。室内壁柱柱头为白色灰塑简化科林斯式，雕刻茛苕卷叶与卷草纹，柱身米黄色带竖向白色凹槽，突出装饰性，与主厅繁复花砖形成等级呼应。室外承重柱柱头为水泥雕刻科林斯式变体，部分加饰中式花饰，柱身米白色水刷石无凹槽，造型厚重满足承重要求，纹样复杂度低于室内壁柱，与阳台、楼梯简化铺装形成功能呼应。</p><p><img src="'+f+'" alt="16"></p><p><img src="'+P+'" alt="17"></p><p><img src="'+x+'" alt="18"></p><p><em>（图15~18：立面柱式对比。作者自摄）</em></p><h3 id="_4-2-园林构筑物" tabindex="-1">4.2 园林构筑物 <a class="header-anchor" href="#_4-2-园林构筑物" aria-label="Permalink to &quot;4.2 园林构筑物&quot;">​</a></h3><p>晚香亭亭柱为中式仿木构造型，雕刻卷草云纹，以水泥水刷石工艺完成西式材料对中式形制的转译，与别墅西式柱式形成功能区分。花藤亭与观澜亭采用西式穹顶与本土洗石米工艺结合，延续西式形式与本土工艺并置逻辑。</p><p><img src="'+C+'" alt="19"></p><p><img src="'+B+'" alt="20"></p><p><em>（图19：晚香亭亭柱。作者自摄）（图20：花藤亭）</em></p><h3 id="_5-1-园主意图-以装饰表达空间等级与全局规划" tabindex="-1">5.1 园主意图：以装饰表达空间等级与全局规划 <a class="header-anchor" href="#_5-1-园主意图-以装饰表达空间等级与全局规划" aria-label="Permalink to &quot;5.1 园主意图：以装饰表达空间等级与全局规划&quot;">​</a></h3><p>铺装纹样随空间等级形成多级梯度，花砖统一模数与边框元素，水磨石分化为三种类型，说明园主有全局规划意识。主厅、高层厅堂、次厅、阳台、卧室、碉楼的铺装差异均为根据空间属性进行的针对性设计。铺装体系是园主个人意志与空间规划意识的直观体现。</p><h3 id="_5-2-建造条件-西式形式与本土工艺的落地转译" tabindex="-1">5.2 建造条件：西式形式与本土工艺的落地转译 <a class="header-anchor" href="#_5-2-建造条件-西式形式与本土工艺的落地转译" aria-label="Permalink to &quot;5.2 建造条件：西式形式与本土工艺的落地转译&quot;">​</a></h3><p>铺装虽采用欧式花砖布局与进口水泥，施工却依托本地工艺。花砖烧制、水磨石现浇打磨均为民国侨乡特色工艺，与碉楼“红毛泥”技术同源。立面柱头以灰塑或水泥雕刻实现，亭柱以水刷石转译中式形制。立园中西融合，不仅是纹样拼贴，更是材料技术层面的跨文化转译。</p><h3 id="_5-3-核心结论" tabindex="-1">5.3 核心结论 <a class="header-anchor" href="#_5-3-核心结论" aria-label="Permalink to &quot;5.3 核心结论&quot;">​</a></h3><p>铺装、立面与构筑物拼贴逻辑一致。地面铺装以多级梯度、统一模数、边框通用及水磨石类型分化，系统地承载了这一营造逻辑。</p><h3 id="_6-1-现有文创产品现状" tabindex="-1">6.1 现有文创产品现状 <a class="header-anchor" href="#_6-1-现有文创产品现状" aria-label="Permalink to &quot;6.1 现有文创产品现状&quot;">​</a></h3><p>开平现有文创以碉楼剪影、骑楼立面，醒狮文化等宏观符号直接复制为主，同质化明显。立园铺装几何纹样、团花单元、水磨石肌理等细部符号未被系统应用。</p><p><img src="'+S+'" alt="21"></p><p><img src="'+T+'" alt="22"></p><p><img src="'+A+'" alt="23"></p><p><img src="'+D+'" alt="24"></p><p><img src="'+v+'" alt="25"></p><p><em>（图20~24：开平现有文创产品。作者自摄）</em></p><h3 id="_6-2-铺装符号的转译优势与建议" tabindex="-1">6.2 铺装符号的转译优势与建议 <a class="header-anchor" href="#_6-2-铺装符号的转译优势与建议" aria-label="Permalink to &quot;6.2 铺装符号的转译优势与建议&quot;">​</a></h3><p>铺装纹样具有单元化结构，团花单元、锯齿纹、棋盘格纹等可独立提取，缩放连续排布，适配多种产品。水磨石与碉楼混凝土工艺同源，承载侨乡近代建造技术物质记忆。建议提取团花单元、边框纹样及水磨石肌理与配色，应用于文创产品设计与表面处理，为开平文创提供细部符号与工艺肌理层面的补充资源。</p><p>本报告以立园地面铺装为切茹口，完成纹样类型、空间分布与拼贴逻辑分析。研究表明，立园铺装是以多级梯度、统一模数、边框通用为特征的全局规划结果，是空间功能、园主意愿与本土工艺共同作用的产物。调研收获在于掌握从细部切入、以小见大的建筑观察方法。局限在于考察时间仅一天，未能系统记录全园区铺装。仓东村、塘口墟与赤坎古镇可作为后续研究方向。</p><p>[1] 谭金花. 开平碉楼与村落的建筑装饰研究[M]. 广州：广东人民出版社，2019.</p><p>[2] 钱毅. 近代乡土建筑：开平碉楼[M]. 北京：中国建筑工业出版社，2015.</p>',83)])])}const F=s(V,[["render",E]]);export{$ as __pageData,F as default};
